import os
import time

def get_modified_timestamps(directory):
    """
    Recursively traverses a directory and its subdirectories, collecting a list of files and their modified timestamps.

    Args:
        directory (str): The path to the directory to traverse.

    Returns:
        dict: A dictionary where keys are file names and values are their modified timestamps.
    """
    modified_timestamps = {}

    try:
        for root, dirs, files in os.walk(directory):
            for file in files:
                file_path = os.path.join(root, file)
                modified_timestamp = time.localtime(os.path.getmtime(file_path))
                modified_timestamps[file] = time.strftime("%Y-%m-%d %H:%M:%S", modified_timestamp)

    except Exception as e:
        print(f"Error occurred while traversing directory: {e}")

    return modified_timestamps


def main():
    directory = input("Enter the path to the directory to traverse: ")
    modified_timestamps = get_modified_timestamps(directory)

    if modified_timestamps:
        print("Files and their modified timestamps:")
        for file, timestamp in modified_timestamps.items():
            print(f"{file}: {timestamp}")
    else:
        print("No files found in the specified directory.")


if __name__ == "__main__":
    main()
